{
  "domain_analysis": {
    "business_context": "A courier-tracking feature is being specified for customer-facing delivery visibility. Two internal stakeholder teams have submitted directly contradictory requirements regarding whether courier GPS location should be shown to customers during active deliveries.",
    "bounded_context": "Delivery Tracking / Last-Mile Visibility",
    "ubiquitous_language": [
      { "term": "Courier", "definition": "The driver or delivery person physically transporting a package from origin to destination" },
      { "term": "Real-time location", "definition": "GPS coordinates of the courier, updated at frequent intervals during an active delivery" },
      { "term": "Active delivery", "definition": "The state of an order between courier pickup and customer handoff" },
      { "term": "Delivery visibility", "definition": "The degree to which a customer can observe the progress of their in-transit order" },
      { "term": "Courier retention", "definition": "The ability of the business to keep couriers working on the platform over time" }
    ]
  },

  "business_rules": [],

  "acceptance_criteria": [],

  "edge_cases": [
    { "scenario": "Courier is stationary for extended period (e.g., traffic, multi-stop route)", "expected_behavior": "Cannot define — depends on resolution of core contradiction. Exact GPS would expose idle time; abstracted status would not." },
    { "scenario": "Courier deviates significantly from expected route", "expected_behavior": "Cannot define — exact GPS reveals deviation to customer (potential complaints); hiding location leaves customer uninformed about delay." },
    { "scenario": "Courier is near customer address but delivering to neighbor/building", "expected_behavior": "Cannot define — exact GPS at this proximity raises safety/surveillance concerns most acutely." },
    { "scenario": "Customer repeatedly refreshes or screenshots courier location", "expected_behavior": "Cannot define — this is the exact surveillance behavior Operations is concerned about, but Customer Success sees as core value." }
  ],

  "business_impact": {
    "financial": "This is a two-sided marketplace problem. Showing exact location may improve customer conversion and retention (Customer Success claim), but losing couriers increases acquisition cost, delivery delays, and service degradation (Operations claim). Both sides carry significant revenue risk — the business cannot operate without either customers or couriers.",
    "operational": "If couriers leave the platform due to surveillance concerns, delivery capacity drops, SLAs degrade, and remaining couriers face higher load — creating a retention death spiral. Conversely, if customers lack delivery visibility, support ticket volume increases and NPS drops.",
    "user": "Customers want confidence their delivery is progressing. Couriers want dignity and autonomy in their work. These are both legitimate user needs that are currently framed as mutually exclusive but may not be.",
    "risk": "CRITICAL: Building either requirement as specified will actively damage the other stakeholder group. There is also potential regulatory risk — sharing exact courier GPS with customers may violate worker privacy regulations in certain jurisdictions (e.g., GDPR, state-level worker surveillance laws).",
    "stakeholders_affected": [
      { "group": "Customers", "impact": "Delivery experience and trust in the platform. Want to know their package is on its way and when it will arrive." },
      { "group": "Couriers", "impact": "Workplace dignity, sense of autonomy, and retention. Exact GPS sharing creates a panopticon dynamic that drives attrition." },
      { "group": "Customer Success team", "impact": "Owns customer satisfaction metrics. Believes transparency drives differentiation and retention." },
      { "group": "Operations team", "impact": "Owns courier supply and fulfillment reliability. Losing drivers threatens the entire delivery operation." },
      { "group": "Legal/Compliance", "impact": "NOT YET CONSULTED — worker location data sharing has regulatory implications that neither team has addressed." },
      { "group": "Business leadership", "impact": "Must arbitrate a marketplace-level tradeoff between demand-side experience and supply-side retention. This is a strategic decision, not a feature decision." }
    ]
  },

  "confidence": {
    "level": 20,
    "reasoning": "Two non-negotiable requirements from equally authoritative stakeholder teams are in direct, irreconcilable contradiction. No acceptance criteria can be defined because implementing either requirement as stated violates the other. Additionally, legal/regulatory review has not been conducted on worker location data sharing, which could invalidate the Customer Success requirement entirely. This is not a specification that can be built — it is a business conflict that must be resolved by leadership before any implementation begins.",
    "high_confidence_areas": [
      "The contradiction is real and irreconcilable as currently stated",
      "Both stakeholder concerns are legitimate business risks",
      "This is a two-sided marketplace problem requiring strategic arbitration",
      "Legal/compliance review is missing and necessary"
    ],
    "low_confidence_areas": [
      "Whether a middle-ground solution (e.g., abstracted progress indicators, ETA-only, zone-level location) would satisfy both teams",
      "The actual magnitude of courier attrition caused by location sharing",
      "The actual magnitude of customer satisfaction improvement from exact GPS visibility",
      "Regulatory requirements in the jurisdictions where couriers operate"
    ],
    "assumptions": [
      "Both teams have authority to set requirements in their domain",
      "Neither team has been told their requirement is subordinate to the other",
      "No leadership decision has been made to prioritize one side of the marketplace over the other",
      "Legal review of worker GPS data sharing has not been conducted"
    ]
  },

  "escalations": [
    {
      "type": "contradiction",
      "description": "Customer Success requires exact courier GPS to be shown to customers at all times. Operations requires courier location to NEVER be shown to customers. These are logically irreconcilable as stated. This is not a technical ambiguity — it is a fundamental business conflict between demand-side experience and supply-side retention in a two-sided marketplace.",
      "affected_stakeholders": ["Customers", "Couriers", "Customer Success", "Operations", "Business Leadership"],
      "options": [
        "A: Implement Customer Success requirement (exact GPS) — accepts courier attrition risk",
        "B: Implement Operations requirement (no location) — accepts customer satisfaction risk",
        "C: Escalate to business leadership to define a compromise policy (e.g., abstracted progress like 'X stops away', ETA-only, zone-level location) that gives customers confidence without creating courier surveillance",
        "D: Conduct data analysis on both claims before deciding — measure actual courier attrition correlated with tracking, and actual customer satisfaction lift from GPS visibility"
      ],
      "recommendation": "Option C with Option D as prerequisite. This is a STRATEGIC decision, not a feature decision. Neither team should unilaterally win. Leadership must define the marketplace balance. Before that meeting, both teams should be required to bring data supporting their claims. A likely resolution is abstracted delivery progress (ETA, status milestones, zone-level proximity) that satisfies the customer's real need (confidence the delivery is progressing) without exposing the courier's exact movements. Additionally, Legal/Compliance must be brought in before any location-sharing design is finalized."
    },
    {
      "type": "missing_context",
      "description": "No legal or regulatory review has been conducted on sharing worker GPS data with end consumers. In multiple jurisdictions, this may constitute worker surveillance requiring explicit consent, data protection impact assessments, or may be prohibited outright.",
      "affected_stakeholders": ["Legal/Compliance", "Couriers", "Business Leadership"],
      "options": [
        "Proceed without legal review (high risk)",
        "Block feature until legal review is complete",
        "Design for minimum data exposure while legal review is conducted in parallel"
      ],
      "recommendation": "Legal review must be initiated immediately and must complete before any courier location data is exposed to customers, regardless of how the stakeholder conflict is resolved."
    }
  ],

  "rejection_reasons": [
    { "violation": "Specification contains irreconcilable contradiction between two authoritative stakeholder requirements", "business_rule_broken": "Cannot encode business rules when the business has not decided what the rules are" },
    { "violation": "No legal/regulatory review of worker location data sharing", "business_rule_broken": "Worker privacy and data protection compliance must be established before designing location-sharing features" }
  ]
}

